    18→    public function store(Request $request, Project $project)
    19→    {
    20→        $this->authorize('update', $project);
    21→
    22→        $validated = $request->validate([
    23→            'title'                      => 'required|string|max:255',
    24→            'description'                => 'nullable|string',
    25→            'priority'                   => 'required|in:high,medium,low',
    26→            'estimated_hours'            => 'nullable|numeric|min:0',
    27→            'status'                     => 'required|in:backlog,in_progress,testing,done',
    28→            'subtasks'                   => 'nullable|array',
    29→            'subtasks.*.title'           => 'required|string|max:255',
    30→            'subtasks.*.estimated_hours' => 'nullable|numeric|min:0',
    31→        ]);
    32→
    33→        $maxPosition = $project->tasks()->where('status', $validated['status'])->max('position') ?? -1;
    34→        $validated['position'] = $maxPosition + 1;
    35→
    36→        $task = $project->tasks()->create(
    37→            collect($validated)->except('subtasks')->toArray()
    38→        );
    39→
    40→        foreach ($validated['subtasks'] ?? [] as $subtaskData) {
    41→            $task->subtasks()->create($subtaskData);
    42→        }
    43→
    44→        return redirect()->route('projects.show', $project)->with('success', 'Tarea creada.');
    45→    }
